    39→// WaitForFileExists polls until at least one file matches the glob pattern
    40→// relative to dir, or fails the test after timeout. Handles the race where an
    41→// interactive agent's prompt pattern appears before file writes land on disk.
    42→func WaitForFileExists(t *testing.T, dir string, glob string, timeout time.Duration) {
    43→	t.Helper()
    44→	pattern := filepath.Join(dir, glob)
    45→	deadline := time.Now().Add(timeout)
    46→	for {
    47→		matches, err := filepath.Glob(pattern)
    48→		require.NoError(t, err)
    49→		if len(matches) > 0 {
    50→			return
    51→		}
    52→		if time.Now().After(deadline) {
    53→			t.Fatalf("expected files matching %s in %s within %s", glob, dir, timeout)
    54→		}
    55→		time.Sleep(500 * time.Millisecond)
    56→	}
    57→}
