    59→// AssertNewCommits polls until at least `atLeast` new commits exist since setup,
    60→// or fails after 20 seconds. Polling handles the race where an interactive
    61→// agent's prompt pattern appears before its git commit lands on disk.
    62→func AssertNewCommits(t *testing.T, s *RepoState, atLeast int) {
    63→	t.Helper()
    64→	AssertNewCommitsWithTimeout(t, s, atLeast, 20*time.Second)
    65→}
    66→
    67→// AssertNewCommitsWithTimeout is like AssertNewCommits but with a configurable
    68→// timeout. Use this when WaitFor may settle on stale pane content (e.g.
    69→// multi-turn interactive tests where the previous turn's prompt is still
    70→// visible), giving the agent more time to complete its commit.
    71→func AssertNewCommitsWithTimeout(t *testing.T, s *RepoState, atLeast int, timeout time.Duration) {
    72→	t.Helper()
    73→	deadline := time.Now().Add(timeout)
    74→	for {
    75→		out := GitOutput(t, s.Dir, "log", "--oneline", s.HeadBefore+"..HEAD")
    76→		var lines []string
    77→		if out != "" {
    78→			lines = strings.Split(strings.TrimSpace(out), "\n")
    79→		}
    80→		if len(lines) >= atLeast {
    81→			return
    82→		}
    83→		if time.Now().After(deadline) {
    84→			t.Fatalf("expected at least %d new commit(s), got %d after %s", atLeast, len(lines), timeout)
    85→		}
    86→		time.Sleep(500 * time.Millisecond)
    87→	}
    88→}
