    90→// WaitForCheckpoint polls until the checkpoint branch advances from its
    91→// initial state, or fails the test after timeout. Use this before any
    92→// assertions that depend on the checkpoint branch (post-commit hook is async).
    93→func WaitForCheckpoint(t *testing.T, s *RepoState, timeout time.Duration) {
    94→	t.Helper()
    95→	deadline := time.Now().Add(timeout)
    96→	for time.Now().Before(deadline) {
    97→		after := GitOutput(t, s.Dir, "rev-parse", "entire/checkpoints/v1")
    98→		if after != s.CheckpointBefore {
    99→			return
   100→		}
   101→		time.Sleep(200 * time.Millisecond)
   102→	}
   103→	t.Fatalf("checkpoint branch did not advance within %s", timeout)
   104→}
