   106→// shadowBranches returns all shadow branches (entire/*) excluding entire/checkpoints/*.
   107→func shadowBranches(t *testing.T, dir string) []string {
   108→	t.Helper()
   109→	branches := GitOutput(t, dir, "for-each-ref", "--format=%(refname:short)", "refs/heads/entire/")
   110→	var shadow []string
   111→	for _, b := range strings.Split(branches, "\n") {
   112→		b = strings.TrimSpace(b)
   113→		if b == "" || strings.HasPrefix(b, "entire/checkpoints") {
   114→			continue
   115→		}
   116→		shadow = append(shadow, b)
   117→	}
   118→	return shadow
   119→}
