   248→// WaitForSessionIdle polls the session state files in .git/entire-sessions/
   249→// until no session has phase "active", or fails the test after timeout.
   250→// This handles the race where an agent's prompt pattern appears in the TUI
   251→// before the turn-end hook has completed (transitioning ACTIVE → IDLE).
   252→func WaitForSessionIdle(t *testing.T, dir string, timeout time.Duration) {
   253→	t.Helper()
   254→	stateDir := filepath.Join(dir, ".git", "entire-sessions")
   255→	deadline := time.Now().Add(timeout)
   256→	for time.Now().Before(deadline) {
   257→		entries, err := os.ReadDir(stateDir)
   258→		if err != nil {
   259→			// Directory may not exist yet; keep polling
   260→			time.Sleep(200 * time.Millisecond)
   261→			continue
   262→		}
   263→		anyActive := false
   264→		for _, entry := range entries {
   265→			if entry.IsDir() || !strings.HasSuffix(entry.Name(), ".json") || strings.HasSuffix(entry.Name(), ".tmp") {
   266→				continue
   267→			}
   268→			data, err := os.ReadFile(filepath.Join(stateDir, entry.Name()))
   269→			if err != nil {
   270→				continue
   271→			}
   272→			var state struct {
   273→				Phase string `json:"phase"`
   274→			}
   275→			if err := json.Unmarshal(data, &state); err != nil {
   276→				continue
   277→			}
   278→			if state.Phase == "active" {
   279→				anyActive = true
   280→				break
   281→			}
   282→		}
   283→		if !anyActive {
   284→			return
   285→		}
   286→		time.Sleep(200 * time.Millisecond)
   287→	}
   288→	t.Fatalf("session(s) did not transition to idle within %s", timeout)
   289→}
