   328→// ValidateCheckpointDeep performs comprehensive validation of checkpoint metadata
   329→// on the checkpoint branch, including transcript JSONL validity, content hash
   330→// verification, and prompt content checking.
   331→func ValidateCheckpointDeep(t *testing.T, dir string, v DeepCheckpointValidation) {
   332→	t.Helper()
   333→
   334→	// Basic metadata validation
   335→	AssertCheckpointExists(t, dir, v.CheckpointID)
   336→	AssertCheckpointMetadataComplete(t, dir, v.CheckpointID)
   337→
   338→	if v.Strategy != "" {
   339→		meta := ReadCheckpointMetadata(t, dir, v.CheckpointID)
   340→		assert.Equal(t, v.Strategy, meta.Strategy,
   341→			"checkpoint %s: strategy mismatch", v.CheckpointID)
   342→	}
   343→
   344→	if len(v.FilesTouched) > 0 {
   345→		AssertCheckpointFilesTouched(t, dir, v.CheckpointID, v.FilesTouched)
   346→	}
   347→
   348→	path := CheckpointPath(v.CheckpointID)
   349→
   350→	// Validate session metadata exists and has checkpoint_id
   351→	sessionBlob := fmt.Sprintf("entire/checkpoints/v1:%s/0/metadata.json", path)
   352→	sessionRaw := gitOutputSafe(dir, "show", sessionBlob)
   353→	if assert.NotEmpty(t, sessionRaw, "session metadata should exist at %s", sessionBlob) {
   354→		var sessionMeta map[string]any
   355→		if assert.NoError(t, json.Unmarshal([]byte(sessionRaw), &sessionMeta)) {
   356→			assert.Equal(t, v.CheckpointID, sessionMeta["checkpoint_id"],
   357→				"session metadata checkpoint_id should match")
   358→			assert.NotEmpty(t, sessionMeta["created_at"], "session metadata should have created_at")
   359→		}
   360→	}
   361→
   362→	// Validate transcript is valid JSONL
   363→	transcriptBlob := fmt.Sprintf("entire/checkpoints/v1:%s/0/full.jsonl", path)
   364→	transcriptRaw := gitOutputSafe(dir, "show", transcriptBlob)
   365→	if assert.NotEmpty(t, transcriptRaw, "transcript should exist at %s", transcriptBlob) {
   366→		lines := strings.Split(transcriptRaw, "\n")
   367→		nonEmpty := 0
   368→		for _, line := range lines {
   369→			if strings.TrimSpace(line) != "" {
   370→				nonEmpty++
   371→			}
   372→		}
   373→		assert.Positive(t, nonEmpty, "transcript should have at least one line")
   374→
   375→		for _, expected := range v.ExpectedTranscriptContent {
   376→			assert.Contains(t, transcriptRaw, expected,
   377→				"transcript should contain %q", expected)
   378→		}
   379→
   380→		// Validate content hash
   381→		hashBlob := fmt.Sprintf("entire/checkpoints/v1:%s/0/content_hash.txt", path)
   382→		hashRaw := gitOutputSafe(dir, "show", hashBlob)
   383→		if hashRaw != "" {
   384→			hash := sha256.Sum256([]byte(transcriptRaw))
   385→			expectedHash := "sha256:" + hex.EncodeToString(hash[:])
   386→			assert.Equal(t, expectedHash, strings.TrimSpace(hashRaw),
   387→				"content hash should match transcript SHA-256")
   388→		}
   389→	}
   390→
   391→	// Validate prompt.txt if expected prompts specified
   392→	if len(v.ExpectedPrompts) > 0 {
   393→		promptBlob := fmt.Sprintf("entire/checkpoints/v1:%s/0/prompt.txt", path)
   394→		promptRaw := gitOutputSafe(dir, "show", promptBlob)
   395→		for _, expected := range v.ExpectedPrompts {
   396→			assert.Contains(t, promptRaw, expected,
   397→				"prompt.txt should contain %q", expected)
   398→		}
   399→	}
   400→}
