   216→func loadJSONMap(path, description string) (map[string]json.RawMessage, error) {
   217→	data, err := os.ReadFile(path)
   218→	if err != nil {
   219→		return nil, fmt.Errorf("read %s at %s: %w", description, path, err)
   220→	}
   221→
   222→	var parsed map[string]json.RawMessage
   223→	if err := json.Unmarshal(data, &parsed); err != nil {
   224→		return nil, fmt.Errorf("parse %s at %s: %w", description, path, err)
   225→	}
   226→	if parsed == nil {
   227→		parsed = make(map[string]json.RawMessage)
   228→	}
   229→	return parsed, nil
   230→}
