   232→func ensureGitInfoExcludeContains(repoDir, entry string) error {
   233→	excludePath := filepath.Join(repoDir, ".git", "info", "exclude")
   234→
   235→	data, err := os.ReadFile(excludePath)
   236→	if err != nil && !errors.Is(err, os.ErrNotExist) {
   237→		return fmt.Errorf("read %s: %w", excludePath, err)
   238→	}
   239→
   240→	normalized := strings.ReplaceAll(string(data), "\r\n", "\n")
   241→	for _, line := range strings.Split(normalized, "\n") {
   242→		if strings.TrimSpace(line) == entry {
   243→			return nil
   244→		}
   245→	}
   246→
   247→	var b strings.Builder
   248→	if len(data) > 0 {
   249→		b.Write(data)
   250→		if data[len(data)-1] != '\n' {
   251→			b.WriteByte('\n')
   252→		}
   253→	}
   254→	b.WriteString(entry)
   255→	b.WriteByte('\n')
   256→
   257→	if err := os.MkdirAll(filepath.Dir(excludePath), 0o755); err != nil {
   258→		return fmt.Errorf("create %s: %w", filepath.Dir(excludePath), err)
   259→	}
   260→	if err := os.WriteFile(excludePath, []byte(b.String()), 0o644); err != nil {
   261→		return fmt.Errorf("write %s: %w", excludePath, err)
   262→	}
   263→	return nil
   264→}
