   508→// CheckpointIDs lists all checkpoint IDs from the tree at the tip of the
   509→// checkpoint branch. It parses the two-level directory structure
   510→// ({prefix}/{suffix}/metadata.json) and returns the concatenated IDs.
   511→func CheckpointIDs(t *testing.T, dir string) []string {
   512→	t.Helper()
   513→	out := gitOutputSafe(dir, "ls-tree", "-r", "--name-only", "entire/checkpoints/v1")
   514→	if out == "" {
   515→		return nil
   516→	}
   517→	seen := map[string]bool{}
   518→	var ids []string
   519→	for _, line := range strings.Split(strings.TrimSpace(out), "\n") {
   520→		// Match {prefix}/{suffix}/metadata.json (top-level, not session-level)
   521→		parts := strings.Split(line, "/")
   522→		if len(parts) == 3 && parts[2] == "metadata.json" {
   523→			id := parts[0] + parts[1]
   524→			if !seen[id] {
   525→				seen[id] = true
   526→				ids = append(ids, id)
   527→			}
   528→		}
   529→	}
   530→	return ids
   531→}
