   569→// WaitForSessionMetadata polls until session metadata exists on the checkpoint
   570→// branch for the given checkpoint ID and session index, then returns it.
   571→// This handles the race where the checkpoint branch advances before session
   572→// metadata is fully committed.
   573→func WaitForSessionMetadata(t *testing.T, dir string, checkpointID string, sessionIndex int, timeout time.Duration) SessionMetadata {
   574→	t.Helper()
   575→
   576→	path := fmt.Sprintf("%s/%d/metadata.json", CheckpointPath(checkpointID), sessionIndex)
   577→	blob := "entire/checkpoints/v1:" + path
   578→
   579→	deadline := time.Now().Add(timeout)
   580→	for time.Now().Before(deadline) {
   581→		raw := gitOutputSafe(dir, "show", blob)
   582→		if raw != "" {
   583→			var meta SessionMetadata
   584→			if err := json.Unmarshal([]byte(raw), &meta); err != nil {
   585→				t.Fatalf("unmarshal session metadata from %s: %v", blob, err)
   586→			}
   587→			return meta
   588→		}
   589→		time.Sleep(500 * time.Millisecond)
   590→	}
   591→	t.Fatalf("session metadata %s did not appear within %s", blob, timeout)
   592→	return SessionMetadata{}
   593→}
