   595→// SetupBareRemote creates a bare git repo, adds it as "origin", and pushes
   596→// the initial commit. Returns the bare repo path.
   597→func SetupBareRemote(t *testing.T, s *RepoState) string {
   598→	t.Helper()
   599→
   600→	var bareDir string
   601→	if os.Getenv("E2E_KEEP_REPOS") != "" {
   602→		var err error
   603→		bareDir, err = os.MkdirTemp("", "e2e-bare-*")
   604→		if err != nil {
   605→			t.Fatalf("create bare remote dir: %v", err)
   606→		}
   607→		t.Logf("E2E_KEEP_REPOS: bare remote will be preserved at %s", bareDir)
   608→	} else {
   609→		bareDir = t.TempDir()
   610→	}
